import 'package:uuid/uuid.dart';import '../models/sync_conflict.dart';import '../models/sync_queue_item.dart';class SyncQueueService{List<SyncQueueItem> buildQueue(List<SyncConflict> conflicts){final out=<SyncQueueItem>[];for(final c in conflicts){switch(c.type){case SyncConflictType.localOnly:out.add(SyncQueueItem(id:const Uuid().v4(),path:c.path,action:SyncQueueAction.upload,status:SyncQueueStatus.pending));break;case SyncConflictType.remoteOnly:out.add(SyncQueueItem(id:const Uuid().v4(),path:c.path,action:SyncQueueAction.download,status:SyncQueueStatus.pending));break;case SyncConflictType.bothChanged:out.add(SyncQueueItem(id:const Uuid().v4(),path:c.path,action:SyncQueueAction.validateOnly,status:SyncQueueStatus.pending,errorCode:'conflictDetected'));break;case SyncConflictType.identical:out.add(SyncQueueItem(id:const Uuid().v4(),path:c.path,action:SyncQueueAction.validateOnly,status:SyncQueueStatus.skipped));break;}}return out;}}
